const llmOutput = $json.output || $json.text || $json.response || "";

let sql = String(llmOutput).trim();

// Nettoyage des éventuels blocs markdown
sql = sql
  .replace(/^```sql/i, "")
  .replace(/^```/i, "")
  .replace(/```$/i, "")
  .trim();

// Supprime un éventuel point-virgule final
sql = sql.replace(/;+\s*$/g, "").trim();

const forbiddenKeywords = [
  "INSERT",
  "UPDATE",
  "DELETE",
  "DROP",
  "ALTER",
  "TRUNCATE",
  "CREATE",
  "REPLACE",
  "GRANT",
  "REVOKE",
  "EXEC",
  "EXECUTE",
  "MERGE",
  "CALL"
];

const upperSql = sql.toUpperCase();

// Vérifie que ce n’est pas vide
if (!sql) {
  throw new Error("La réponse du LLM est vide.");
}

// Vérifie que c’est bien une requête SELECT
if (!upperSql.startsWith("SELECT")) {
  throw new Error("La requête SQL doit commencer par SELECT.");
}

// Bloque les requêtes multiples
if (sql.includes(";")) {
  throw new Error("Les requêtes multiples sont interdites.");
}

// Bloque les mots-clés dangereux
for (const keyword of forbiddenKeywords) {
  const regex = new RegExp(`\\b${keyword}\\b`, "i");
  if (regex.test(sql)) {
    throw new Error(`Mot-clé SQL interdit détecté : ${keyword}`);
  }
}

// Bloque les commentaires SQL
if (/--|\/\*/.test(sql)) {
  throw new Error("Les commentaires SQL sont interdits.");
}

// Optionnel : force un LIMIT si absent
if (!/\bLIMIT\b/i.test(sql)) {
  sql += " LIMIT 100";
}

return [
  {
    json: {
      sql,
      isValid: true
    }
  }
];
